import{_ as t,C as s,o,c as i,a2 as a,E as l}from"./chunks/framework.BKG_UbFK.js";const f=JSON.parse('{"title":"Tableau de bord","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/dashboard.md","filePath":"fr/features/dashboard.md"}'),n={name:"fr/features/dashboard.md"};function d(c,e,u,p,h,m){const r=s("Screenshot");return o(),i("div",null,[e[0]||(e[0]=a('<h1 id="tableau-de-bord" tabindex="-1">Tableau de bord <a class="header-anchor" href="#tableau-de-bord" aria-label="Permalink to &quot;Tableau de bord&quot;">​</a></h1><p>Le Tableau de bord est la page d&#39;accueil du panneau Clearance. Il fournit un résumé en un coup d&#39;œil de l&#39;état d&#39;autorisation de votre application - aucune configuration requise.</p><h2 id="ce-qu-il-affiche" tabindex="-1">Ce qu&#39;il affiche <a class="header-anchor" href="#ce-qu-il-affiche" aria-label="Permalink to &quot;Ce qu&#39;il affiche&quot;">​</a></h2><ul><li><strong>Total des rôles</strong> - nombre total de rôles Spatie.</li><li><strong>Total des gardes</strong> - nombre total de gardes gérés par Clearance (voir <a href="/clearance-docs/fr/features/guards.html">Gardes</a>).</li><li><strong>Total des permissions</strong> - nombre total de permissions Spatie.</li><li><strong>Groupes de permissions</strong> - le nombre de groupes de permissions distincts, dérivé du préfixe de nommage (le <code>group</code> dans <code>group-action</code>, ex. <code>orders</code> dans <code>orders-create</code>). Voir <a href="/clearance-docs/fr/features/permissions.html">Permissions</a> pour la convention de nommage.</li><li><strong>Assignations de rôle contextuelles</strong> - le nombre d&#39;attributions de rôle limitées à une instance de modèle spécifique (un Store, un Tenant, un Project). Voir <a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a>.</li><li><strong>Top 5 des rôles par nombre d&#39;utilisateurs</strong> - les cinq rôles ayant le plus d&#39;utilisateurs assignés, classés.</li></ul>',4)),l(r,{src:"/screenshots/dashboard-page.png",alt:"Tableau de bord Clearance affichant le nombre de rôles, gardes et permissions",caption:"Le Tableau de bord résume les rôles, gardes, permissions, groupes, assignations contextuelles, et les rôles principaux."}),e[1]||(e[1]=a('<h2 id="acceder-au-tableau-de-bord" tabindex="-1">Accéder au Tableau de bord <a class="header-anchor" href="#acceder-au-tableau-de-bord" aria-label="Permalink to &quot;Accéder au Tableau de bord&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nom de route</th><th>Description</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>Tableau de bord</td></tr></tbody></table><p>La lecture du Tableau de bord nécessite la permission <code>clearance-access</code>, comme toute autre section du panneau. Voir <a href="/clearance-docs/fr/features/super-admin.html#panel-access-fine-grained-write-permissions">Super Admin</a> pour le tableau complet de contrôle d&#39;accès.</p><h2 id="integrer-le-composant" tabindex="-1">Intégrer le composant <a class="header-anchor" href="#integrer-le-composant" aria-label="Permalink to &quot;Intégrer le composant&quot;">​</a></h2><p>Le Tableau de bord est un composant Livewire autonome. Montez-le n&#39;importe où dans vos propres layouts, à la place de - ou en complément de - la route prête à l&#39;emploi <code>/clearance</code> :</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/features/permissions.html">Permissions</a> - gérer la liste de permissions alimentant les compteurs du Tableau de bord.</li><li><a href="/clearance-docs/fr/features/roles.html">Rôles</a> - gérer les rôles derrière la statistique &quot;top 5 par nombre d&#39;utilisateurs&quot;.</li><li><a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a> - ce qu&#39;est une assignation de rôle contextuelle.</li></ul>',8))])}const g=t(n,[["render",d]]);export{f as __pageData,g as default};
